import{_ as p,C as c,o as s,c as d,a2 as a,b as o,w as t,a as r,E as i,a3 as l}from"./chunks/framework.B72_uj9U.js";const C=JSON.parse('{"title":"Self-Review Patterns","description":"","frontmatter":{"title":"Self-Review Patterns","status":"complete"},"headers":[],"relativePath":"research/concepts/testing-and-verification/self-review.md","filePath":"research/concepts/testing-and-verification/self-review.md"}'),h={name:"research/concepts/testing-and-verification/self-review.md"};function u(g,e,f,m,y,v){const n=c("Mermaid");return s(),d("div",null,[e[10]||(e[10]=a('<h1 id="self-review-patterns" tabindex="-1">Self-Review Patterns <a class="header-anchor" href="#self-review-patterns" aria-label="Permalink to &quot;Self-Review Patterns&quot;">​</a></h1><blockquote><p>How coding agents review their own output — from re-reading generated code to dedicated reviewer agents — and why self-review is the verification layer that catches what tests, linters, and type checkers cannot.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>External verification tools — test suites, linters, type checkers — catch <strong>syntactic and structural</strong> errors. A missing import, a type mismatch, a failing assertion: these are objective, mechanically detectable problems. But a large class of defects lives beyond the reach of automated tools:</p><ul><li><strong>Logic errors</strong>: the code runs without errors but computes the wrong result</li><li><strong>Incorrect algorithms</strong>: an O(n³) solution where O(n log n) was needed</li><li><strong>Wrong business logic</strong>: the feature works but doesn&#39;t match the requirement</li><li><strong>Missed edge cases</strong>: null inputs, empty arrays, concurrent access, Unicode</li><li><strong>Incomplete implementations</strong>: the happy path works but error handling is absent</li><li><strong>Semantic misunderstandings</strong>: the agent misread the task and solved the wrong problem</li></ul><p>Self-review is how agents catch these <strong>semantic</strong> mistakes. It is the verification layer that sits above automated tooling and below human review — filling the gap where machines can check syntax but only reasoning can check intent.</p><p>Among the 17 agents studied, self-review ranges from nonexistent to architecturally enforced. The spectrum is wide, and the impact on code quality is measurable.</p><hr><h2 id="the-self-review-spectrum" tabindex="-1">The Self-Review Spectrum <a class="header-anchor" href="#the-self-review-spectrum" aria-label="Permalink to &quot;The Self-Review Spectrum&quot;">​</a></h2><p>Not all agents treat self-review equally. The approaches fall along a spectrum of increasing formality and enforcement:</p>',10)),(s(),o(l,null,{default:t(()=>[i(n,{id:"mermaid-59",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22**No%20Review**%3Cbr%2F%3EGenerate%20%26amp%3B%20submit%3Cbr%2F%3E%3Cbr%2F%3EMini%20SWE%20Agent%3Cbr%2F%3EAnte%3Cbr%2F%3EPi%20Coding%20Agent%22%5D%0A%20%20%20%20B%5B%22**Implicit**%3Cbr%2F%3EModel%20reflects%20naturally%3Cbr%2F%3E%3Cbr%2F%3EMost%20LLMs%20do%3Cbr%2F%3Esome%20of%20this%20by%20default%22%5D%0A%20%20%20%20C%5B%22**Prompted**%3Cbr%2F%3ESystem%20prompt%20says%20'review'%3Cbr%2F%3E%3Cbr%2F%3EClaude%20Code%3Cbr%2F%3EGemini%20CLI%3Cbr%2F%3EGoose%22%5D%0A%20%20%20%20D%5B%22**Enforced**%3Cbr%2F%3ERuntime%20blocks%20without%20review%3Cbr%2F%3E%3Cbr%2F%3EForgeCode%3Cbr%2F%3EJunie%20CLI%3Cbr%2F%3EDroid%20(auto)%22%5D%0A%20%20%20%20E%5B%22**Dedicated**%3Cbr%2F%3ESeparate%20agent%20reviews%20output%3Cbr%2F%3E%3Cbr%2F%3ETongAgents%3Cbr%2F%3ECapy%20(Captain)%3Cbr%2F%3EAider%20(Architect)%22%5D%0A%20%20%20%20A%20--%3E%20B%20--%3E%20C%20--%3E%20D%20--%3E%20E%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[r(" Loading... ",-1)])]),_:1})),e[11]||(e[11]=a('<table tabindex="0"><thead><tr><th>Level</th><th>Description</th><th>Agents</th><th>Failure Mode</th></tr></thead><tbody><tr><td><strong>No self-review</strong></td><td>Generate code, submit immediately</td><td>Mini SWE Agent, Ante, Pi Coding Agent</td><td>All semantic errors reach the user</td></tr><tr><td><strong>Implicit</strong></td><td>LLM naturally pauses to reflect before finishing</td><td>All LLMs (varying degree)</td><td>Reflection is shallow, inconsistent</td></tr><tr><td><strong>Prompted</strong></td><td>System prompt instructs review before completion</td><td>Claude Code, Gemini CLI, Goose, OpenCode</td><td>Model may skip review under token pressure</td></tr><tr><td><strong>Enforced</strong></td><td>Runtime requires verification pass; blocks completion</td><td>ForgeCode, Junie CLI</td><td>Adds latency; can loop on false negatives</td></tr><tr><td><strong>Dedicated reviewer</strong></td><td>Separate agent or model reviews the primary output</td><td>TongAgents, Capy, Aider (Architect), Droid</td><td>Doubles cost; reviewer may echo generator</td></tr></tbody></table><p>The critical insight: <strong>prompted self-review is unreliable under pressure.</strong> When the context window is filling up, when the task seems straightforward, when the model is confident — prompted review gets skipped. Enforced and dedicated-reviewer patterns pay a cost in latency and tokens but deliver more consistent quality.</p><hr><h2 id="re-reading-generated-code" tabindex="-1">Re-Reading Generated Code <a class="header-anchor" href="#re-reading-generated-code" aria-label="Permalink to &quot;Re-Reading Generated Code&quot;">​</a></h2><p>The simplest form of self-review: after generating or editing a file, read it back and verify correctness.</p><h3 id="the-pattern" tabindex="-1">The Pattern <a class="header-anchor" href="#the-pattern" aria-label="Permalink to &quot;The Pattern&quot;">​</a></h3>',6)),(s(),o(l,null,{default:t(()=>[i(n,{id:"mermaid-163",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22Edit%20file%22%5D%20--%3E%20B%5B%22Read%20file%3Cbr%2F%3E(fresh%20load)%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22Evaluate%3Cbr%2F%3Ecorrectness%22%5D%0A%20%20%20%20C%20--%3E%20D%5B%22Fix%20if%20wrong%22%5D%0A%20%20%20%20B%20--%3E%20E%5B%22File%20contents%20are%3Cbr%2F%3Ere-tokenized%20fresh%20%E2%80%94%3Cbr%2F%3Enot%20from%20memory%22%5D%0A%20%20%20%20C%20--%3E%20F%5B%22'Does%20this%3Cbr%2F%3Ematch%20what%20I%3Cbr%2F%3Eintended%3F'%22%5D%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[r(" Loading... ",-1)])]),_:1})),e[12]||(e[12]=a(`<h3 id="claude-code-verify-phase-as-architecture" tabindex="-1">Claude Code: Verify Phase as Architecture <a class="header-anchor" href="#claude-code-verify-phase-as-architecture" aria-label="Permalink to &quot;Claude Code: Verify Phase as Architecture&quot;">​</a></h3><p>Claude Code&#39;s three-phase loop makes re-reading structural:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Phase 1: GATHER CONTEXT</span></span>
<span class="line"><span>  • Grep, Read, Glob, LSP → understand the codebase</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Phase 2: TAKE ACTION</span></span>
<span class="line"><span>  • Edit, Bash → make changes</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Phase 3: VERIFY RESULTS          ← Self-review happens here</span></span>
<span class="line"><span>  • Read edited files            ← Re-read what was just written</span></span>
<span class="line"><span>  • Run test suite again</span></span>
<span class="line"><span>  • Check for type errors (LSP)</span></span>
<span class="line"><span>  • Run linters</span></span>
<span class="line"><span>  • Compare before/after</span></span>
<span class="line"><span>  • Search for related issues</span></span></code></pre></div><p>The tool-chaining pattern shows explicit re-verification after every edit:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>1. Grep(&quot;error message&quot;)           → finds the relevant file</span></span>
<span class="line"><span>2. Read(&quot;src/auth/session.ts&quot;)     → understands the code</span></span>
<span class="line"><span>3. Bash(&quot;npm test -- session&quot;)     → sees the failing test</span></span>
<span class="line"><span>4. Edit(&quot;src/auth/session.ts&quot;)     → fixes the issue</span></span>
<span class="line"><span>5. Bash(&quot;npm test -- session&quot;)     → verifies the fix passes    ← re-verify</span></span>
<span class="line"><span>6. Read(&quot;src/auth/session.ts&quot;)     → confirms the edit is clean ← re-read</span></span></code></pre></div><p>Anthropic&#39;s finding: Claude performs <strong>&quot;dramatically better&quot;</strong> when it can verify its own work. Without verification criteria, the user becomes the only feedback loop.</p><h3 id="the-fresh-eyes-problem" tabindex="-1">The &quot;Fresh Eyes&quot; Problem <a class="header-anchor" href="#the-fresh-eyes-problem" aria-label="Permalink to &quot;The &quot;Fresh Eyes&quot; Problem&quot;">​</a></h3><p>Re-reading has a fundamental limitation: <strong>the same model reviewing its own output tends to confirm rather than critique.</strong> The LLM generated the code moments ago — its hidden state is primed to see the output as correct. This is analogous to a writer proofreading immediately after writing: they see what they intended, not what they typed.</p><p>Mitigations observed across agents:</p><ul><li><strong>Different model for review</strong> (Aider&#39;s Architect mode, evaluator-optimizer pattern)</li><li><strong>Structured review criteria</strong> (ForgeCode&#39;s enforcement questions)</li><li><strong>Time delay / context reset</strong> (Goose&#39;s conversation reset on retry)</li><li><strong>External grounding</strong> (running tests, checking types — objective signals)</li></ul><hr><h2 id="diff-review-before-commit" tabindex="-1">Diff Review Before Commit <a class="header-anchor" href="#diff-review-before-commit" aria-label="Permalink to &quot;Diff Review Before Commit&quot;">​</a></h2><p>Rather than re-reading entire files, several agents review the <strong>diff</strong> — the precise set of changes — before committing or submitting.</p><h3 id="why-diffs-are-better-than-full-re-reads" tabindex="-1">Why Diffs Are Better Than Full Re-Reads <a class="header-anchor" href="#why-diffs-are-better-than-full-re-reads" aria-label="Permalink to &quot;Why Diffs Are Better Than Full Re-Reads&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Full re-read:  4,000 lines of code → 4,000 tokens to review</span></span>
<span class="line"><span>Diff review:   12 lines changed     → 12 tokens to review (focused attention)</span></span></code></pre></div><p>Reviewing the diff concentrates the model&#39;s attention on exactly what changed, reducing the chance of missing errors in the modified lines while avoiding distraction from the (presumably correct) unchanged code.</p><h3 id="codex-op-review-as-first-class-operation" tabindex="-1">Codex: Op::Review as First-Class Operation <a class="header-anchor" href="#codex-op-review-as-first-class-operation" aria-label="Permalink to &quot;Codex: Op::Review as First-Class Operation&quot;">​</a></h3><p>Codex treats review as a first-class operation in its event system, not an afterthought:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Codex&#39;s operation enum includes Review alongside core operations</span></span>
<span class="line"><span style="color:#CBA6F7;">enum</span><span style="color:#F9E2AF;font-style:italic;"> Op</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    UserMessage</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    AgentMessage</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ExecApproval</span><span style="color:#9399B2;">  {</span><span style="color:#CDD6F4;"> id</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> decision</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> ReviewDecision</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    PatchApproval</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> id</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> decision</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> ReviewDecision</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Review</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> },</span><span style="color:#6C7086;font-style:italic;">           // ← Dedicated review operation</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Undo</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> num_turns </span><span style="color:#9399B2;">},</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ThreadRollback</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// The ReviewDecision enum gates whether changes proceed</span></span>
<span class="line"><span style="color:#CBA6F7;">match</span><span style="color:#CDD6F4;"> decision </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ReviewDecision</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Denied</span><span style="color:#94E2D5;">  =&gt;</span><span style="color:#CBA6F7;"> return</span><span style="color:#F9E2AF;font-style:italic;"> Err</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">ToolError</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Rejected</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">..</span><span style="color:#9399B2;">)),</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ReviewDecision</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Abort</span><span style="color:#94E2D5;">   =&gt;</span><span style="color:#CBA6F7;"> return</span><span style="color:#F9E2AF;font-style:italic;"> Err</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">ToolError</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Aborted</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ReviewDecision</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Approved</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span><span style="color:#6C7086;font-style:italic;"> /* proceed with change */</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ReviewDecision</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">ApprovedExecpolicyAmendment</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">amendment</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        // Update execution policy for future commands</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The <code>/review</code> slash command supports three modes:</p><ul><li><strong>Branch diff</strong>: compare current branch against base</li><li><strong>Uncommitted changes</strong>: review working directory modifications</li><li><strong>Commit review</strong>: review specific commits</li></ul><p>However, Codex&#39;s review is <strong>human-facing</strong>, not agent-self-review. The <code>Op::Review</code> operation presents changes to the user for approval, rather than the agent reviewing its own work autonomously.</p><h3 id="droid-automated-diff-review-with-guidelines" tabindex="-1">Droid: Automated Diff Review with Guidelines <a class="header-anchor" href="#droid-automated-diff-review-with-guidelines" aria-label="Permalink to &quot;Droid: Automated Diff Review with Guidelines&quot;">​</a></h3><p>Droid has the most mature <strong>automated</strong> diff-review pattern among the 17 agents. Its auto-review loop runs on every PR:</p>`,24)),(s(),o(l,null,{default:t(()=>[i(n,{id:"mermaid-259",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22PR%20opened%22%5D%20--%3E%20B%5B%22Filter%20check%3Cbr%2F%3E(skip%20draft%2C%3Cbr%2F%3Ebot%2C%20WIP)%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22Read%20diff%20%2B%3Cbr%2F%3Eapply%20path-%3Cbr%2F%3Especific%20rules%22%5D%0A%20%20%20%20C%20--%3E%20D%5B%22Generate%3Cbr%2F%3Ereview%20with%3Cbr%2F%3Ecomments%22%5D%0A%20%20%20%20E%5B%22.droid.yaml%3Cbr%2F%3Eguidelines%22%5D%20--%3E%20C%0A"})]),fallback:t(()=>[...e[2]||(e[2]=[r(" Loading... ",-1)])]),_:1})),e[13]||(e[13]=a(`<p>The <code>.droid.yaml</code> configuration makes review criteria explicit and path-specific:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;">review</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  guidelines</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">    -</span><span style="color:#89B4FA;"> path</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;**/api/**&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">      guideline</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;All API endpoints must have input validation&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    -</span><span style="color:#89B4FA;"> path</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;**/models/**&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">      guideline</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;Database models must have proper indexes&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    -</span><span style="color:#89B4FA;"> path</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;**/*.test.*&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">      guideline</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;Tests should cover edge cases, not just happy path&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">  auto_review</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    enabled</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#89B4FA;">    draft</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> false</span><span style="color:#6C7086;font-style:italic;">        # skip draft PRs</span></span>
<span class="line"><span style="color:#89B4FA;">    bot</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> false</span><span style="color:#6C7086;font-style:italic;">          # skip bot-generated PRs</span></span></code></pre></div><p>Review output includes:</p><ul><li>PR summary (what changed and why)</li><li>Per-file summaries</li><li>Actionable review comments matching path-specific guidelines</li><li>CI failure analysis and suggested fixes (<code>github_action_repair: true</code>)</li><li>Skip-reason transparency (why a review was omitted)</li></ul><h3 id="warp-gpu-rendered-interactive-diff-review" tabindex="-1">Warp: GPU-Rendered Interactive Diff Review <a class="header-anchor" href="#warp-gpu-rendered-interactive-diff-review" aria-label="Permalink to &quot;Warp: GPU-Rendered Interactive Diff Review&quot;">​</a></h3><p>Warp&#39;s GPU-rendered terminal enables a visual diff review experience impossible in text-only terminals:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Interactive Code Review                                      │</span></span>
<span class="line"><span>│  File: src/auth/login.ts                                     │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │  - const token = jwt.sign(payload, secret);            │  │</span></span>
<span class="line"><span>│  │  + const session = await createSession(user.id);       │  │</span></span>
<span class="line"><span>│  │  + await session.setSecure(true);                      │  │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────────────┘  │</span></span>
<span class="line"><span>│  💬 &quot;Should we also set the SameSite attribute?&quot;             │</span></span>
<span class="line"><span>│  [Accept] [Reject] [Edit] [Comment]                          │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p>Key capabilities:</p><ul><li>Syntax-highlighted diffs with rich color (beyond 256-color)</li><li>Per-hunk accept/reject (granular control, not all-or-nothing)</li><li>Inline comment annotations</li><li>Agent can revise changes based on review feedback</li><li>Batch operations (accept all, reject all)</li></ul><p>Warp&#39;s Full Terminal Use (FTU) also enables a form of self-verification: the agent observes its own command output in the live terminal buffer, effectively reading back the results of its actions.</p><hr><h2 id="multi-pass-generation" tabindex="-1">Multi-Pass Generation <a class="header-anchor" href="#multi-pass-generation" aria-label="Permalink to &quot;Multi-Pass Generation&quot;">​</a></h2><p>Rather than generating code once and hoping it&#39;s correct, several agents use multiple passes — each with a different focus.</p><h3 id="the-general-pattern" tabindex="-1">The General Pattern <a class="header-anchor" href="#the-general-pattern" aria-label="Permalink to &quot;The General Pattern&quot;">​</a></h3>`,14)),(s(),o(l,null,{default:t(()=>[i(n,{id:"mermaid-344",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22**Pass%201%3A%20GENERATE**%3Cbr%2F%3EProduce%20the%20initial%20solution.%3Cbr%2F%3E%3Cbr%2F%3EOptimized%20for%3Cbr%2F%3Espeed%2Fcoverage%22%5D%0A%20%20%20%20B%5B%22**Pass%202%3A%20REVIEW**%3Cbr%2F%3EReview%20against%20requirements.%3Cbr%2F%3EFix%20logic%20errors.%3Cbr%2F%3E%3Cbr%2F%3EOptimized%20for%3Cbr%2F%3Ecorrectness%22%5D%0A%20%20%20%20C%5B%22**Pass%203%3A%20VERIFY**%3Cbr%2F%3ERun%20tests%2C%20linters%2C%20types.%3Cbr%2F%3EFix%20any%20failures.%3Cbr%2F%3E%3Cbr%2F%3EOptimized%20for%3Cbr%2F%3Emechanical%20proof%22%5D%0A%20%20%20%20A%20--%3E%20B%20--%3E%20C%0A"})]),fallback:t(()=>[...e[3]||(e[3]=[r(" Loading... ",-1)])]),_:1})),e[14]||(e[14]=a(`<h3 id="aider-s-architect-mode-reasoning-editing-as-separate-passes" tabindex="-1">Aider&#39;s Architect Mode: Reasoning + Editing as Separate Passes <a class="header-anchor" href="#aider-s-architect-mode-reasoning-editing-as-separate-passes" aria-label="Permalink to &quot;Aider&#39;s Architect Mode: Reasoning + Editing as Separate Passes&quot;">​</a></h3><p>Aider&#39;s Architect mode is the clearest multi-pass pattern among the 17 agents. It splits generation into two phases handled by different models:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Pass 1: REASONING MODEL (o1, o3, R1, Claude)</span></span>
<span class="line"><span>  └─► Describes the solution in natural language</span></span>
<span class="line"><span>  └─► &quot;Change function X to handle null inputs by adding a guard clause...&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pass 2: EDITING MODEL (Sonnet, GPT-4o, DeepSeek)</span></span>
<span class="line"><span>  └─► Translates the plan into concrete file edits</span></span>
<span class="line"><span>  └─► Produces search/replace blocks or unified diffs</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pass 3: AUTOMATED VERIFICATION</span></span>
<span class="line"><span>  └─► Lint (tree-sitter built-in + custom linters)</span></span>
<span class="line"><span>  └─► Test (--auto-test runs test suite, feeds failures back)</span></span>
<span class="line"><span>  └─► Fix (LLM attempts to fix any lint/test failures)</span></span></code></pre></div><p>The benchmark evidence is striking — even pairing a model with <strong>itself</strong> improves results by splitting reasoning from editing:</p><table tabindex="0"><thead><tr><th>Configuration</th><th>SWE-Bench Score</th></tr></thead><tbody><tr><td>o1-preview alone</td><td>79.7%</td></tr><tr><td>o1-preview architect + o1-mini editor</td><td><strong>85.0%</strong></td></tr><tr><td>Sonnet alone</td><td>77.4%</td></tr><tr><td>Sonnet architect + Sonnet editor</td><td><strong>80.5%</strong></td></tr></tbody></table><p>The improvement comes from <strong>forcing the model to articulate its reasoning</strong> before committing to code. The natural-language plan serves as an intermediate representation that the editing model can verify against.</p><h3 id="forgecode-thinking-budget-as-multi-pass-control" tabindex="-1">ForgeCode: Thinking Budget as Multi-Pass Control <a class="header-anchor" href="#forgecode-thinking-budget-as-multi-pass-control" aria-label="Permalink to &quot;ForgeCode: Thinking Budget as Multi-Pass Control&quot;">​</a></h3><p>ForgeCode controls the depth of reasoning per phase through a <strong>progressive thinking policy</strong>:</p>`,8)),(s(),o(l,null,{default:t(()=>[i(n,{id:"mermaid-410",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22Messages%201%E2%80%9310%3A%20VERY%20HIGH%20thinking%20budget%3Cbr%2F%3E%E2%86%90%20Planning%20phase%20(deep%20reasoning)%22%5D%0A%20%20%20%20B%5B%22Messages%2011%2B%3A%20LOW%20thinking%20budget%3Cbr%2F%3E%E2%86%90%20Execution%20phase%20(fast%20iteration)%22%5D%0A%20%20%20%20C%5B%22Verification%3A%20HIGH%20thinking%20budget%3Cbr%2F%3E%E2%86%90%20Review%20phase%20(deep%20analysis)%22%5D%0A%20%20%20%20D%5B%22The%20thinking%20budget%20switches%20BACK%20to%20high%3Cbr%2F%3Eduring%20verification%20%E2%80%94%3Cbr%2F%3Eforcing%20deep%20review%20after%20fast%20execution.%22%5D%0A%20%20%20%20A%20--%3E%20B%20--%3E%20C%20--%3E%20D%0A"})]),fallback:t(()=>[...e[4]||(e[4]=[r(" Loading... ",-1)])]),_:1})),e[15]||(e[15]=a('<p>This is multi-pass by resource allocation: the agent is cheap and fast during implementation, then expensive and careful during review. The switch from low to high thinking budget during verification effectively creates a &quot;second opinion&quot; from a more deliberate version of the same model.</p><h3 id="droid-specification-mode" tabindex="-1">Droid: Specification Mode <a class="header-anchor" href="#droid-specification-mode" aria-label="Permalink to &quot;Droid: Specification Mode&quot;">​</a></h3><p>Droid separates planning from execution using different models:</p><ol><li><strong>Reasoning model</strong> (Claude Opus, o3) generates a detailed implementation spec: technical details, file changes, edge cases, test requirements</li><li><strong>Execution model</strong> (potentially cheaper) implements the spec</li></ol><p>The spec acts as an intermediate verification artifact — the implementation can be checked against it, and the spec itself can be reviewed before execution begins.</p><hr><h2 id="critic-reviewer-agent-patterns" tabindex="-1">Critic / Reviewer Agent Patterns <a class="header-anchor" href="#critic-reviewer-agent-patterns" aria-label="Permalink to &quot;Critic / Reviewer Agent Patterns&quot;">​</a></h2><p>The most sophisticated self-review approach: a <strong>separate agent</strong> whose sole job is to evaluate the primary agent&#39;s output.</p><h3 id="the-evaluator-optimizer-pattern" tabindex="-1">The Evaluator-Optimizer Pattern <a class="header-anchor" href="#the-evaluator-optimizer-pattern" aria-label="Permalink to &quot;The Evaluator-Optimizer Pattern&quot;">​</a></h3>',9)),(s(),o(l,null,{default:t(()=>[i(n,{id:"mermaid-445",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22**Generator**%3Cbr%2F%3E(Agent%20A)%3Cbr%2F%3E%3Cbr%2F%3EProduces%20code%22%5D%0A%20%20%20%20B%5B%22**Evaluator**%3Cbr%2F%3E(Agent%20B)%3Cbr%2F%3E%3Cbr%2F%3EReviews%20output%22%5D%0A%20%20%20%20C%5B%22Different%20model%2C%3Cbr%2F%3Edifferent%20system%20prompt%2C%3Cbr%2F%3Edifferent%20temperature%22%5D%0A%20%20%20%20A%20--%3E%7Coutput%7C%20B%0A%20%20%20%20B%20--%3E%7Cfeedback%7C%20A%0A%20%20%20%20A%20-.-%3E%20C%0A%20%20%20%20B%20-.-%3E%20C%0A"})]),fallback:t(()=>[...e[5]||(e[5]=[r(" Loading... ",-1)])]),_:1})),e[16]||(e[16]=a(`<p>Using a different model for evaluation mitigates the &quot;fresh eyes&quot; problem. The evaluator was not primed by the generation process, so it approaches the output with genuine scrutiny rather than confirmation bias.</p><h3 id="tongagents-dedicated-verifier-in-multi-agent-pipeline" tabindex="-1">TongAgents: Dedicated Verifier in Multi-Agent Pipeline <a class="header-anchor" href="#tongagents-dedicated-verifier-in-multi-agent-pipeline" aria-label="Permalink to &quot;TongAgents: Dedicated Verifier in Multi-Agent Pipeline&quot;">​</a></h3><p>TongAgents implements the clearest separation between execution and verification among the 17 agents (architecture is inferred — no public source code):</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Orchestrator: &quot;Configure nginx with SSL&quot;</span></span>
<span class="line"><span>  → Planner:   &quot;Steps: 1) install nginx, 2) generate cert, 3) configure, 4) test&quot;</span></span>
<span class="line"><span>  → Executor:  runs step 1, returns output</span></span>
<span class="line"><span>  → Verifier:  &quot;nginx installed successfully ✓ — proceed&quot;</span></span>
<span class="line"><span>  → Executor:  runs step 2, returns error</span></span>
<span class="line"><span>  → Planner:   &quot;Revise step 2: install certbot first&quot;</span></span>
<span class="line"><span>  → Executor:  runs revised step 2</span></span>
<span class="line"><span>  → Verifier:  &quot;cert generated ✓ — proceed&quot;</span></span></code></pre></div><p>The Verifier agent checks <strong>each step&#39;s output</strong> before the pipeline advances. This is finer-grained than reviewing the final result — errors are caught at the earliest possible point.</p>`,5)),(s(),o(l,null,{default:t(()=>[i(n,{id:"mermaid-459",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20ORC%5B%22Orchestrator%20Agent%22%5D%0A%20%20%20%20%20%20%20%20P%5B%22**Planning%20Agent**%3Cbr%2F%3E-%20Analyze%20task%3Cbr%2F%3E-%20Generate%20plan%3Cbr%2F%3E-%20Revise%20on%20failure%22%5D%0A%20%20%20%20%20%20%20%20E%5B%22**Execution%20Agent**%3Cbr%2F%3E-%20Run%20commands%3Cbr%2F%3E-%20Handle%20errors%3Cbr%2F%3E-%20Report%20results%22%5D%0A%20%20%20%20%20%20%20%20V%5B%22**Verification%20Agent**%3Cbr%2F%3E-%20Check%20each%20step%20output%3Cbr%2F%3E-%20Validate%20final%20state%3Cbr%2F%3E-%20Approve%20or%20reject%22%5D%0A%20%20%20%20end%0A%20%20%20%20P%20--%3E%20E%20--%3E%20V%0A"})]),fallback:t(()=>[...e[6]||(e[6]=[r(" Loading... ",-1)])]),_:1})),e[17]||(e[17]=a(`<h3 id="forgecode-three-agent-architecture" tabindex="-1">ForgeCode: Three-Agent Architecture <a class="header-anchor" href="#forgecode-three-agent-architecture" aria-label="Permalink to &quot;ForgeCode: Three-Agent Architecture&quot;">​</a></h3><p>ForgeCode&#39;s Muse/Forge/Sage split creates review through architectural separation:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Role</th><th>Access</th><th>Self-Review Function</th></tr></thead><tbody><tr><td><strong>Forge</strong></td><td>Implementation</td><td>Read + Write</td><td>Builder — produces code</td></tr><tr><td><strong>Muse</strong></td><td>Planning</td><td>Read-only</td><td>Plans without side effects; reviews Forge&#39;s approach</td></tr><tr><td><strong>Sage</strong></td><td>Research</td><td>Read-only (internal)</td><td>Deep analysis engine; returns summaries</td></tr></tbody></table><p>Muse&#39;s read-only constraint is key: because it <strong>cannot modify files</strong>, it is forced to think before acting. This architectural constraint prevents the common failure mode where agents rush to implementation without adequate planning.</p><h3 id="capy-captain-build-split" tabindex="-1">Capy: Captain / Build Split <a class="header-anchor" href="#capy-captain-build-split" aria-label="Permalink to &quot;Capy: Captain / Build Split&quot;">​</a></h3><p>Capy enforces review through role separation:</p><ul><li><strong>Captain</strong> (Planning): <em>&quot;You are a technical architect who PLANS but never IMPLEMENTS.&quot;</em> Can read codebases, ask questions, write specifications. <strong>Cannot write code.</strong></li><li><strong>Build</strong> (Execution): <em>&quot;You are an autonomous AI agent...&quot;</em> Can edit files, run tests, open PRs. <strong>Cannot ask clarifying questions.</strong></li></ul><p>The architectural enforcement creates a natural quality gate:</p><blockquote><p>Because Build cannot request clarification, Captain must produce thorough specs. Because Captain cannot write code, it doesn&#39;t skip ahead to implementation.</p></blockquote><p>The trade-off: rigidity adds overhead for simple tasks. Creating a specification for a one-line bug fix is wasteful. But for complex, multi-file changes, the forced planning-then-execution split catches misunderstandings before they become code.</p><hr><h2 id="reflection-prompts" tabindex="-1">Reflection Prompts <a class="header-anchor" href="#reflection-prompts" aria-label="Permalink to &quot;Reflection Prompts&quot;">​</a></h2><p>The content of self-review prompts matters enormously. Vague instructions (&quot;review your code&quot;) produce shallow review. Specific, evidence-demanding questions force genuine verification.</p><h3 id="forgecode-s-enforcement-question" tabindex="-1">ForgeCode&#39;s Enforcement Question <a class="header-anchor" href="#forgecode-s-enforcement-question" aria-label="Permalink to &quot;ForgeCode&#39;s Enforcement Question&quot;">​</a></h3><p>The single most impactful reflection prompt observed across all 17 agents:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>&quot;What evidence proves this objective is actually complete?&quot;</span></span></code></pre></div><p>This question demands <strong>evidence</strong>, not assertion. The agent cannot simply say &quot;I believe it&#39;s done&quot; — it must point to test results, output comparisons, or other concrete proof. This was reportedly <strong>&quot;the biggest single improvement&quot;</strong> to ForgeCode&#39;s quality, particularly with GPT 5.4, which would implement solutions, express confidence, and stop before the task was actually complete.</p><p>The enforcement flow:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># ForgeCode verification enforcement (pseudocode)</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> check_completion</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">agent_state</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CBA6F7;"> not</span><span style="color:#CDD6F4;"> agent_state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">verification_skill_called</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # Runtime blocks completion — no opt-out</span></span>
<span class="line"><span style="color:#89B4FA;">        inject_reminder</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">agent_state</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">        agent_state</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">require_verification</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#CBA6F7;"> False</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # Verification skill asks the critical question</span></span>
<span class="line"><span style="color:#CDD6F4;">    verification_result </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> agent_state</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run_verification</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        prompt</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">        Before marking this task complete, answer:</span></span>
<span class="line"><span style="color:#A6E3A1;">        1. What was requested?</span></span>
<span class="line"><span style="color:#A6E3A1;">        2. What was actually done?</span></span>
<span class="line"><span style="color:#A6E3A1;">        3. What evidence exists that it worked?</span></span>
<span class="line"><span style="color:#A6E3A1;">        4. What is still missing?</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    )</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> verification_result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">has_gaps</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#CBA6F7;"> False</span><span style="color:#6C7086;font-style:italic;">  # Agent must address gaps before completing</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CBA6F7;"> True</span></span></code></pre></div><h3 id="categories-of-effective-reflection-prompts" tabindex="-1">Categories of Effective Reflection Prompts <a class="header-anchor" href="#categories-of-effective-reflection-prompts" aria-label="Permalink to &quot;Categories of Effective Reflection Prompts&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>EVIDENCE-DEMANDING:</span></span>
<span class="line"><span>  &quot;What test output proves this works?&quot;</span></span>
<span class="line"><span>  &quot;Show me the diff that addresses the requirement.&quot;</span></span>
<span class="line"><span>  &quot;What error did you fix, and how do you know it&#39;s fixed?&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>EDGE-CASE PROBING:</span></span>
<span class="line"><span>  &quot;What happens with empty input?&quot;</span></span>
<span class="line"><span>  &quot;What happens with null/undefined?&quot;</span></span>
<span class="line"><span>  &quot;What happens under concurrent access?&quot;</span></span>
<span class="line"><span>  &quot;What happens when the file doesn&#39;t exist?&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SCOPE-CHECKING:</span></span>
<span class="line"><span>  &quot;Does this change affect other parts of the codebase?&quot;</span></span>
<span class="line"><span>  &quot;Are there callers of this function that need updating?&quot;</span></span>
<span class="line"><span>  &quot;Does the documentation still match the implementation?&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>REQUIREMENT-MATCHING:</span></span>
<span class="line"><span>  &quot;Restate the original requirement in your own words.&quot;</span></span>
<span class="line"><span>  &quot;Does every part of the requirement have corresponding code?&quot;</span></span>
<span class="line"><span>  &quot;What requirement am I NOT addressing, and why?&quot;</span></span></code></pre></div><h3 id="how-system-prompts-shape-self-review-behavior" tabindex="-1">How System Prompts Shape Self-Review Behavior <a class="header-anchor" href="#how-system-prompts-shape-self-review-behavior" aria-label="Permalink to &quot;How System Prompts Shape Self-Review Behavior&quot;">​</a></h3><p>Claude Code&#39;s system prompt shapes verification behavior through guidelines rather than enforcement. The best-practices documentation emphasizes providing <strong>verification criteria</strong> in the task description:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>WEAK (no verification criteria):</span></span>
<span class="line"><span>  &quot;Fix the login bug.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>STRONG (verification criteria embedded):</span></span>
<span class="line"><span>  &quot;Fix the login bug. Verify by running the test suite.</span></span>
<span class="line"><span>   Confirm that the session token is set correctly by</span></span>
<span class="line"><span>   checking the response headers.&quot;</span></span></code></pre></div><p>The difference in outcome is measurable: with verification criteria, the model runs tests, checks outputs, and catches its own errors. Without them, it often stops after the first edit that &quot;looks right.&quot;</p><hr><h2 id="how-agents-catch-their-own-mistakes" tabindex="-1">How Agents Catch Their Own Mistakes <a class="header-anchor" href="#how-agents-catch-their-own-mistakes" aria-label="Permalink to &quot;How Agents Catch Their Own Mistakes&quot;">​</a></h2><p>Beyond high-level review patterns, agents have specific mechanisms for detecting and correcting errors at the tool-call level.</p><h3 id="openhands-error-→-observation-→-self-correction" tabindex="-1">OpenHands: Error → Observation → Self-Correction <a class="header-anchor" href="#openhands-error-→-observation-→-self-correction" aria-label="Permalink to &quot;OpenHands: Error → Observation → Self-Correction&quot;">​</a></h3><p>OpenHands converts malformed tool calls into structured error observations that the agent can act on:</p>`,30)),(s(),o(l,null,{default:t(()=>[i(n,{id:"mermaid-608",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22LLM%20generates%3Cbr%2F%3Emalformed%20tool%20call%3Cbr%2F%3E(wrong%20args%2C%20bad%20format)%22%5D%0A%20%20%20%20B%5B%22Runtime%20converts%20to%3Cbr%2F%3EErrorObservation%3Cbr%2F%3Ewith%20structured%20error%20message%22%5D%0A%20%20%20%20C%5B%22Agent%20sees%20error%3Cbr%2F%3Ein%20event%20stream%2C%3Cbr%2F%3Efixes%20the%20call%20on%20next%20step%22%5D%0A%20%20%20%20A%20--%3E%20B%20--%3E%20C%0A%0A%20%20%20%20D%5B%22FunctionCallValidationError%22%5D%20--%3E%20E%5B%22Convert%20to%20ErrorObservation%22%5D%20--%3E%20F%5B%22Agent%20self-corrects%22%5D%0A%20%20%20%20G%5B%22ContextWindowExceededError%22%5D%20--%3E%20H%5B%22Trigger%20condensation%22%5D%20--%3E%20I%5B%22Retry%20with%20shorter%20context%22%5D%0A%20%20%20%20J%5B%22RateLimitError%22%5D%20--%3E%20K%5B%22Exponential%20backoff%22%5D%20--%3E%20L%5B%22Retry%20after%20delay%22%5D%0A%20%20%20%20M%5B%22Sandbox%20timeout%20%2F%20crash%22%5D%20--%3E%20N%5B%22ErrorObservation%22%5D%20--%3E%20O%5B%22Agent%20can%20retry%22%5D%0A"})]),fallback:t(()=>[...e[7]||(e[7]=[r(" Loading... ",-1)])]),_:1})),e[18]||(e[18]=a(`<p>The key design choice: errors are <strong>not fatal</strong>. They become observations in the event stream, giving the agent a chance to self-correct. Every <code>Observation</code> links to its causing <code>Action</code> via a <code>cause</code> field, maintaining causal traceability:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> Event</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">    _id</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#6C7086;font-style:italic;">                   # monotonic sequence number</span></span>
<span class="line"><span style="color:#CDD6F4;">    _cause</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#6C7086;font-style:italic;">                # ID of the event that triggered this one</span></span>
<span class="line"><span style="color:#CDD6F4;">    source</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> EventSource        </span><span style="color:#6C7086;font-style:italic;"># AGENT, USER, ENVIRONMENT</span></span></code></pre></div><h3 id="openhands-stuckdetector-—-breaking-self-reinforcing-loops" tabindex="-1">OpenHands: StuckDetector — Breaking Self-Reinforcing Loops <a class="header-anchor" href="#openhands-stuckdetector-—-breaking-self-reinforcing-loops" aria-label="Permalink to &quot;OpenHands: StuckDetector — Breaking Self-Reinforcing Loops&quot;">​</a></h3><p>When self-correction fails and the agent enters a loop, OpenHands&#39; <code>StuckDetector</code> intervenes. It runs after <strong>every step</strong> with four detection strategies:</p><table tabindex="0"><thead><tr><th>Strategy</th><th>Detection Rule</th><th>Recovery</th></tr></thead><tbody><tr><td><strong>Identical repetition</strong></td><td><code>action[n] == action[n-1] == action[n-2]</code></td><td>Terminate or nudge</td></tr><tr><td><strong>Alternating pattern</strong></td><td><code>action[n] == action[n-2] &amp;&amp; action[n-1] == action[n-3]</code></td><td>Terminate or nudge</td></tr><tr><td><strong>Error loop</strong></td><td>Last K observations are all <code>ErrorObservation</code></td><td>Force condensation</td></tr><tr><td><strong>Empty response</strong></td><td>Last K actions have empty/near-empty content</td><td>Terminate</td></tr></tbody></table><p>Recovery options escalate: <code>LoopRecoveryAction</code> (nudge to try different approach) → force condensation (compress history to break pattern) → <code>AgentStuckInLoopError</code> (terminate). This is meta-self-review: the system reviews whether the agent&#39;s self-correction is actually making progress.</p><h3 id="forgecode-toolcallcorrector-—-fix-before-failing" tabindex="-1">ForgeCode: ToolCallCorrector — Fix Before Failing <a class="header-anchor" href="#forgecode-toolcallcorrector-—-fix-before-failing" aria-label="Permalink to &quot;ForgeCode: ToolCallCorrector — Fix Before Failing&quot;">​</a></h3><p>ForgeCode&#39;s tool-call correction layer intercepts <strong>every</strong> tool call before dispatch and attempts automatic repair:</p>`,8)),(s(),o(l,null,{default:t(()=>[i(n,{id:"mermaid-689",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22LLM%20emits%3Cbr%2F%3Etool%20call%22%5D%0A%20%20%20%20B%5B%22**ToolCallCorrector**%3Cbr%2F%3E%3Cbr%2F%3E1.%20Validate%20args%3Cbr%2F%3E2.%20Pattern%20match%3Cbr%2F%3E3.%20Auto-correct%3Cbr%2F%3E4.%20Gate%20dispatch%22%5D%0A%20%20%20%20C%5B%22Dispatch%20to%3Cbr%2F%3Eactual%20tool%22%5D%0A%20%20%20%20D%5B%22Costs%20~0%20tokens%20vs%3Cbr%2F%3E1000%2B%20for%20re-generation%22%5D%0A%20%20%20%20A%20--%3E%20B%20--%3E%20C%0A%20%20%20%20B%20--%3E%20D%0A"})]),fallback:t(()=>[...e[8]||(e[8]=[r(" Loading... ",-1)])]),_:1})),e[19]||(e[19]=a(`<p>Correction strategies:</p><ul><li><strong>Alias inference</strong>: model uses <code>file</code> instead of <code>file_path</code> → corrected</li><li><strong>Type coercion</strong>: string <code>&quot;42&quot;</code> where number expected → converted to <code>42</code></li><li><strong>Fuzzy enum matching</strong>: <code>&quot;read_File&quot;</code> where <code>&quot;read_file&quot;</code> expected → matched</li><li><strong>Structural repair</strong>: wrong nesting depth → flattened</li></ul><p>The key insight: fixing a tool call <strong>costs ~0 extra tokens</strong> compared to 1,000+ tokens for rejecting the call, generating an error message, having the model re-read the error, and re-generating the call. This is self-correction at the infrastructure layer, invisible to the model.</p><h3 id="goose-argument-coercion" tabindex="-1">Goose: Argument Coercion <a class="header-anchor" href="#goose-argument-coercion" aria-label="Permalink to &quot;Goose: Argument Coercion&quot;">​</a></h3><p>Goose implements a similar pattern through <code>coerce_arguments()</code> in <code>crates/goose/src/agents/reply_parts.rs</code>:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Goose&#39;s argument coercion handles common LLM type mistakes</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// String &quot;42&quot; → Number 42</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// String &quot;true&quot; → Boolean true</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// String &quot;null&quot; → Null</span></span></code></pre></div><p>Beyond type coercion, Goose&#39;s 4-inspector pipeline provides layered self-review at the tool-call level:</p><ol><li><strong>SecurityInspector</strong> — pattern-matching for dangerous commands</li><li><strong>AdversaryInspector</strong> — prompt injection detection in tool arguments</li><li><strong>PermissionInspector</strong> — per-tool permission rules</li><li><strong>RepetitionInspector</strong> — detects tools called repeatedly without progress</li></ol><p>The RepetitionInspector is particularly relevant to self-review: it catches the case where the agent is &quot;trying&quot; but not making progress — a form of failed self-correction that needs external intervention.</p><h3 id="structured-errors-yield-better-self-correction" tabindex="-1">Structured Errors Yield Better Self-Correction <a class="header-anchor" href="#structured-errors-yield-better-self-correction" aria-label="Permalink to &quot;Structured Errors Yield Better Self-Correction&quot;">​</a></h3><p>Across all agents, a consistent finding: <strong>structured error messages yield ~90% self-correction rates vs ~50% for vague errors.</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>VAGUE ERROR (low self-correction rate):</span></span>
<span class="line"><span>  &quot;Error: command failed&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>STRUCTURED ERROR (high self-correction rate):</span></span>
<span class="line"><span>  &quot;Error: FileNotFoundError</span></span>
<span class="line"><span>   File: src/auth/session.ts</span></span>
<span class="line"><span>   Line: 42</span></span>
<span class="line"><span>   Expected: existing file path</span></span>
<span class="line"><span>   Received: src/auth/sessions.ts (note: &#39;sessions&#39; vs &#39;session&#39;)</span></span>
<span class="line"><span>   Suggestion: Did you mean &#39;src/auth/session.ts&#39;?&quot;</span></span></code></pre></div><p>Agents that invest in structured error formatting — OpenHands&#39; <code>ErrorObservation</code>, ForgeCode&#39;s <code>ToolCallCorrector</code>, Aider&#39;s fuzzy edit matching — consistently recover from errors more efficiently than agents that surface raw error strings.</p><h3 id="aider-fuzzy-edit-matching-as-self-correction" tabindex="-1">Aider: Fuzzy Edit Matching as Self-Correction <a class="header-anchor" href="#aider-fuzzy-edit-matching-as-self-correction" aria-label="Permalink to &quot;Aider: Fuzzy Edit Matching as Self-Correction&quot;">​</a></h3><p>Aider implements a progressive fuzzy-matching system when the LLM&#39;s search/replace edits don&#39;t exactly match the file contents:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Level 1: Exact match                          ← fastest</span></span>
<span class="line"><span>Level 2: Strip trailing whitespace</span></span>
<span class="line"><span>Level 3: Ignore leading/trailing blank lines</span></span>
<span class="line"><span>Level 4: Normalized whitespace comparison</span></span>
<span class="line"><span>Level 5: Partial line matching                ← most tolerant</span></span></code></pre></div><p>This is self-correction at the <strong>edit-application layer</strong>: rather than failing and asking the model to regenerate, Aider adapts the edit to match reality. It handles the common case where the model&#39;s mental model of the file is slightly stale.</p><hr><h2 id="the-limits-of-self-review" tabindex="-1">The Limits of Self-Review <a class="header-anchor" href="#the-limits-of-self-review" aria-label="Permalink to &quot;The Limits of Self-Review&quot;">​</a></h2><h3 id="confirmation-bias" tabindex="-1">Confirmation Bias <a class="header-anchor" href="#confirmation-bias" aria-label="Permalink to &quot;Confirmation Bias&quot;">​</a></h3><p>The fundamental challenge: <strong>a model reviewing its own output tends to confirm rather than critique.</strong> The generation process primes the model&#39;s hidden state toward the solution it just produced. Asking it to find flaws in that solution is asking it to overcome its own conditioning.</p><p>Evidence: ForgeCode found that without enforced verification, GPT 5.4 would implement solutions, &quot;sound confident,&quot; and stop — genuinely believing the task was complete when it wasn&#39;t. The model&#39;s self-assessment was systematically over-optimistic.</p><h3 id="diminishing-returns-of-multiple-passes" tabindex="-1">Diminishing Returns of Multiple Passes <a class="header-anchor" href="#diminishing-returns-of-multiple-passes" aria-label="Permalink to &quot;Diminishing Returns of Multiple Passes&quot;">​</a></h3>`,23)),(s(),o(l,null,{default:t(()=>[i(n,{id:"mermaid-789",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22Pass%201%20(generation)%3A%3Cbr%2F%3Ecatches%20~0%25%20of%20own%20errors%3Cbr%2F%3E(it's%20creating%20them)%22%5D%0A%20%20%20%20B%5B%22Pass%202%20(self-review)%3A%3Cbr%2F%3Ecatches%20~40-60%25%20of%20semantic%20errors%22%5D%0A%20%20%20%20C%5B%22Pass%203%20(second%20review)%3A%3Cbr%2F%3Ecatches%20~10-15%25%20more%22%5D%0A%20%20%20%20D%5B%22Pass%204%20(third%20review)%3A%3Cbr%2F%3Ecatches%20~2-5%25%20more%22%5D%0A%20%20%20%20E%5B%22Sharply%20diminishing%20returns%20after%202%20passes.%3Cbr%2F%3EBetter%20to%20spend%20tokens%20on%20a%20DIFFERENT%3Cbr%2F%3Emodel%20or%20approach.%22%5D%0A%20%20%20%20A%20--%3E%20B%20--%3E%20C%20--%3E%20D%20--%3E%20E%0A"})]),fallback:t(()=>[...e[9]||(e[9]=[r(" Loading... ",-1)])]),_:1})),e[20]||(e[20]=a(`<p>The empirical evidence from Aider&#39;s Architect mode confirms this: splitting across two models (even two instances of the same model) outperforms additional passes with a single model. <strong>Diversity of perspective matters more than depth of review.</strong></p><h3 id="when-self-review-fails" tabindex="-1">When Self-Review Fails <a class="header-anchor" href="#when-self-review-fails" aria-label="Permalink to &quot;When Self-Review Fails&quot;">​</a></h3><p>Self-review is least effective for:</p><ul><li><strong>Novel algorithms</strong>: the model has no training-data precedent to compare against</li><li><strong>Subtle concurrency bugs</strong>: require reasoning about interleaved execution paths</li><li><strong>Security vulnerabilities</strong>: models often don&#39;t flag insecure patterns as errors</li><li><strong>Performance regressions</strong>: &quot;correct&quot; code that is dramatically slower</li></ul><p>For these categories, external verification (benchmarks, security scanners, profilers) or human review remains essential.</p><h3 id="the-cost-quality-tradeoff" tabindex="-1">The Cost-Quality Tradeoff <a class="header-anchor" href="#the-cost-quality-tradeoff" aria-label="Permalink to &quot;The Cost-Quality Tradeoff&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Approach</th><th>Extra Tokens</th><th>Error Reduction</th><th>Best For</th></tr></thead><tbody><tr><td>No review</td><td>0</td><td>0%</td><td>Trivial changes</td></tr><tr><td>Single self-review pass</td><td>~500–2000</td><td>~40–60%</td><td>Most edits</td></tr><tr><td>Enforced verification (ForgeCode)</td><td>~1000–3000</td><td>~60–80%</td><td>Complex tasks</td></tr><tr><td>Dedicated reviewer agent</td><td>~2000–5000</td><td>~70–85%</td><td>High-stakes changes</td></tr><tr><td>Different model as reviewer</td><td>~2000–5000</td><td>~75–90%</td><td>Critical production code</td></tr></tbody></table><p>The sweet spot for most agents: <strong>one enforced self-review pass with structured verification criteria</strong>, supplemented by automated tools (tests, lints, types). Going beyond this is justified only for high-stakes changes.</p><hr><h2 id="goose-conversation-reset-as-nuclear-self-correction" tabindex="-1">Goose: Conversation Reset as Nuclear Self-Correction <a class="header-anchor" href="#goose-conversation-reset-as-nuclear-self-correction" aria-label="Permalink to &quot;Goose: Conversation Reset as Nuclear Self-Correction&quot;">​</a></h2><p>Goose implements a unique self-review escape hatch: when self-correction fails repeatedly, it <strong>resets the entire conversation</strong> and retries from scratch.</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> RetryManager</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    attempts</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Arc</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Mutex</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">u32</span><span style="color:#89DCEB;">&gt;&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    repetition_inspector</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Arc</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Mutex</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">RepetitionInspector</span><span style="color:#89DCEB;">&gt;&gt;&gt;&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The flow:</p><ol><li>Execute task</li><li>Run success checks</li><li>If failed and attempts &lt; max: <strong>reset conversation to initial state</strong></li><li>Retry from scratch with a clean context</li></ol><p>This is the most extreme form of self-correction: acknowledging that the current line of reasoning is irrecoverable and starting over. It trades accumulated context for a fresh perspective — an architectural solution to confirmation bias.</p><p>Goose also proactively manages its own context through background tool-pair summarization:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> maybe_summarize_tool_pairs</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;">    provider</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Arc</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">dyn</span><span style="color:#F9E2AF;font-style:italic;"> Provider</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;">    conversation</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">Conversation</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;">    tool_call_cut_off</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> usize</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> JoinHandle</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">(</span><span style="color:#CBA6F7;">usize</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Message</span><span style="color:#9399B2;">)</span><span style="color:#89DCEB;">&gt;&gt;</span></span></code></pre></div><p>Old tool-call/response pairs are summarized and replaced, keeping the context window focused on current work rather than historical details that might anchor the model to failed approaches.</p><hr><h2 id="design-recommendations" tabindex="-1">Design Recommendations <a class="header-anchor" href="#design-recommendations" aria-label="Permalink to &quot;Design Recommendations&quot;">​</a></h2><ol><li><p><strong>Enforce verification, don&#39;t just prompt for it.</strong> ForgeCode&#39;s runtime-enforced verification was &quot;the biggest single improvement&quot; to their quality. Prompted review is unreliable — the model skips it when it feels confident. Make verification a gate, not a suggestion.</p></li><li><p><strong>Demand evidence, not assertions.</strong> &quot;What evidence proves this is complete?&quot; is dramatically more effective than &quot;Review your changes.&quot; The model must point to test output, diff contents, or command results — not just claim correctness.</p></li><li><p><strong>Invest in structured error messages.</strong> The difference between ~50% and ~90% self-correction rates comes down to error message quality. Include file paths, line numbers, expected vs actual values, and suggestions.</p></li><li><p><strong>Fix tool calls at the infrastructure layer.</strong> ForgeCode&#39;s ToolCallCorrector and Goose&#39;s <code>coerce_arguments()</code> fix common mistakes for ~0 tokens. Letting errors reach the model costs 1,000+ tokens per correction cycle.</p></li><li><p><strong>Use a different model for review when stakes are high.</strong> Same-model review suffers from confirmation bias. Even using two instances of the same model (Aider&#39;s Architect pattern) improves quality measurably.</p></li><li><p><strong>Two passes is the sweet spot.</strong> Generate, then review once. Additional passes show sharply diminishing returns. Spend the token budget on diverse verification (tests + lint + type check) rather than repeated self-review.</p></li><li><p><strong>Detect stuck loops and break them.</strong> OpenHands&#39; StuckDetector pattern is essential: self-correction can become self-reinforcing failure. Monitor for repeated actions and escalate to conversation reset or termination.</p></li><li><p><strong>Separate planning from execution architecturally.</strong> Capy&#39;s Captain/Build split, Aider&#39;s Architect mode, and ForgeCode&#39;s Muse/Forge separation all force review through role constraints, not prompt instructions.</p></li></ol><hr><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ol><li><p><strong>Self-review catches what automation cannot.</strong> Tests verify behavior, linters verify syntax, type checkers verify structure — but only self-review catches logic errors, missed requirements, and semantic misunderstandings. It is the verification layer between tooling and human review.</p></li><li><p><strong>Enforcement beats prompting.</strong> Agents that programmatically require verification (ForgeCode, Junie CLI) consistently outperform agents that merely suggest it. The model&#39;s self-assessment is systematically over-optimistic.</p></li><li><p><strong>The biggest wins come from architectural separation.</strong> Splitting generator and reviewer — whether through different models (Aider), different agents (TongAgents, Capy), or different thinking budgets (ForgeCode) — outperforms having a single model review itself more thoroughly.</p></li><li><p><strong>Infrastructure-level correction is nearly free.</strong> Type coercion, alias matching, and fuzzy edit application handle common mistakes at ~0 token cost. Every error that reaches the model costs 1,000+ tokens to resolve.</p></li><li><p><strong>Self-review has hard limits.</strong> Confirmation bias, diminishing returns, and blind spots for novel/concurrent/security issues mean self-review supplements but never replaces external verification and human judgment.</p></li></ol><hr><h2 id="real-world-implementations" tabindex="-1">Real-World Implementations <a class="header-anchor" href="#real-world-implementations" aria-label="Permalink to &quot;Real-World Implementations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Self-Review Strategy</th><th>Key Mechanism</th><th>Reference</th></tr></thead><tbody><tr><td><strong>Aider</strong></td><td>Multi-model Architect mode; fuzzy edit matching; lint-test-fix cycle</td><td>Two-pass generation with separate reasoning and editing models</td><td><a href="./../agents/aider/unique-patterns.html"><code>../agents/aider/unique-patterns.md</code></a></td></tr><tr><td><strong>Ante</strong></td><td>No dedicated self-review</td><td>—</td><td><a href="./../agents/ante/agentic-loop.html"><code>../agents/ante/agentic-loop.md</code></a></td></tr><tr><td><strong>Capy</strong></td><td>Captain/Build architectural split</td><td>Planning agent cannot code; coding agent cannot ask questions</td><td><a href="./../agents/capy/architecture.html"><code>../agents/capy/architecture.md</code></a></td></tr><tr><td><strong>Claude Code</strong></td><td>Gather→Act→Verify three-phase loop; prompted verification</td><td>Re-reads files after editing; runs tests as verification</td><td><a href="./../agents/claude-code/agentic-loop.html"><code>../agents/claude-code/agentic-loop.md</code></a></td></tr><tr><td><strong>Codex</strong></td><td>Op::Review with ReviewDecision enum; human-facing review</td><td><code>/review</code> command for branch diff, uncommitted changes, commits</td><td><a href="./../agents/codex/architecture.html"><code>../agents/codex/architecture.md</code></a></td></tr><tr><td><strong>Droid</strong></td><td>Automated PR review with path-specific guidelines</td><td><code>.droid.yaml</code> review rules; CI failure analysis</td><td><a href="./../agents/droid/agentic-loop.html"><code>../agents/droid/agentic-loop.md</code></a></td></tr><tr><td><strong>ForgeCode</strong></td><td>Runtime-enforced verification; ToolCallCorrector; thinking budget</td><td>Blocks completion without evidence; ~0-token tool-call repair</td><td><a href="./../agents/forgecode/unique-patterns.html"><code>../agents/forgecode/unique-patterns.md</code></a></td></tr><tr><td><strong>Gemini CLI</strong></td><td>Prompted self-review via GEMINI.md guidelines</td><td>Verification criteria in system prompt</td><td><a href="./../agents/gemini-cli/agentic-loop.html"><code>../agents/gemini-cli/agentic-loop.md</code></a></td></tr><tr><td><strong>Goose</strong></td><td>Argument coercion; RepetitionInspector; conversation reset on retry</td><td><code>coerce_arguments()</code> + RetryManager with full context reset</td><td><a href="./../agents/goose/agentic-loop.html"><code>../agents/goose/agentic-loop.md</code></a></td></tr><tr><td><strong>Junie CLI</strong></td><td>Dedicated Verify phase in execution pipeline</td><td>JetBrains inspections as verification step</td><td><a href="./../agents/junie-cli/agentic-loop.html"><code>../agents/junie-cli/agentic-loop.md</code></a></td></tr><tr><td><strong>Mini SWE Agent</strong></td><td>No self-review</td><td>Single-pass generation</td><td><a href="./../agents/mini-swe-agent/agentic-loop.html"><code>../agents/mini-swe-agent/agentic-loop.md</code></a></td></tr><tr><td><strong>OpenCode</strong></td><td>Prompted review via system instructions</td><td>Verification suggested but not enforced</td><td><a href="./../agents/opencode/agentic-loop.html"><code>../agents/opencode/agentic-loop.md</code></a></td></tr><tr><td><strong>OpenHands</strong></td><td>ErrorObservation self-correction; StuckDetector loop breaking</td><td>Malformed calls → structured errors → agent retries</td><td><a href="./../agents/openhands/agentic-loop.html"><code>../agents/openhands/agentic-loop.md</code></a></td></tr><tr><td><strong>Pi Coding Agent</strong></td><td>No dedicated self-review</td><td>—</td><td><a href="./../agents/pi-coding-agent/agentic-loop.html"><code>../agents/pi-coding-agent/agentic-loop.md</code></a></td></tr><tr><td><strong>Sage Agent</strong></td><td>No dedicated self-review</td><td>—</td><td><a href="./../agents/sage-agent/agentic-loop.html"><code>../agents/sage-agent/agentic-loop.md</code></a></td></tr><tr><td><strong>TongAgents</strong></td><td>Dedicated Verifier agent in multi-agent pipeline</td><td>Per-step verification before pipeline advances</td><td><a href="./../agents/tongagents/agentic-loop.html"><code>../agents/tongagents/agentic-loop.md</code></a></td></tr><tr><td><strong>Warp</strong></td><td>GPU-rendered interactive diff review; FTU terminal observation</td><td>Per-hunk accept/reject; agent reads its own terminal output</td><td><a href="./../agents/warp/unique-patterns.html"><code>../agents/warp/unique-patterns.md</code></a></td></tr></tbody></table>`,27))])}const E=p(h,[["render",u]]);export{C as __pageData,E as default};
